Movement.isGrounded = function()
	local root = Utils.getRoot();
	if not root then
		return false;
	end
	local params = RaycastParams.new();
	params.FilterType = Enum.RaycastFilterType.Exclude;
	local char = Utils.getChar();
	if char then
		params.FilterDescendantsInstances = {char};
	end
	local offsets = {Vector3.new(0, 0, 0),Vector3.new(1, 0, 0),Vector3.new(-1, 0, 0),Vector3.new(0, 0, 1),Vector3.new(0, 0, -1)};
	for _, offset in ipairs(offsets) do
		local ray = Workspace:Raycast(root.Position + offset, Vector3.new(0, -5, 0), params);
		if ray then
			return true;
		end
	end
	return false;
end;
Movement.hasObstacleAhead = function(targetPos)
	local root = Utils.getRoot();
	if not root then
		return false;
	end
	local params = RaycastParams.new();
	params.FilterType = Enum.RaycastFilterType.Exclude;
	local char = Utils.getChar();
	if char then
		params.FilterDescendantsInstances = {char};
	end
	local direction = targetPos - root.Position;
	direction = Vector3.new(direction.X, 0, direction.Z);
	if (direction.Magnitude < 0.1) then
		return true;
	end
	direction = direction.Unit;
	local heights = {0.5,1.5,2.5};
	for _, h in ipairs(heights) do
		local ray = Workspace:Raycast(root.Position + Vector3.new(0, h, 0), direction * 4, params);
		if ray then
			return true;
		end
	end
	return false;
end;
Movement.shouldJump = function(targetPos)
	local root = Utils.getRoot();
	if not root then
		return false;
	end
	local params = RaycastParams.new();
	params.FilterType = Enum.RaycastFilterType.Exclude;
	local char = Utils.getChar();
	if char then
		params.FilterDescendantsInstances = {char};
	end
	local targetGroundRay = Workspace:Raycast(targetPos + Vector3.new(0, 5, 0), Vector3.new(0, -15, 0), params);
	local targetGroundY = (targetGroundRay and targetGroundRay.Position.Y) or targetPos.Y;
	local selfGroundRay = Workspace:Raycast(root.Position, Vector3.new(0, -10, 0), params);
	local selfGroundY = (selfGroundRay and selfGroundRay.Position.Y) or root.Position.Y;
	local groundDiff = targetGroundY - selfGroundY;
	if (groundDiff < 1) then
		return false;
	end
	if ((groundDiff >= 1) and (groundDiff < 4)) then
		return Movement.hasObstacleAhead(targetPos);
	end
	if (groundDiff >= 4) then
		return true;
	end
	return false;
end;
